  "test_cases": [
    {
      "case_id": "TC1",
      "description": "测试基本数据类型之间的隐式转换（自动类型提升）",
      "input": "int a = 10; double b = a;",
      "expected_output": "b = 10.0",
      "assertion": "检查int到double的转换是否正确，无精度损失"
    },
    {
      "case_id": "TC2",
      "description": "测试基本数据类型之间的显式转换（强制类型转换）",
      "input": "double c = 10.5; int d = (int) c;",
      "expected_output": "d = 10",
      "assertion": "检查double到int的转换是否正确，截断小数部分"
    },
    {
      "case_id": "TC3",
      "description": "测试引用类型之间的向上转型（多态）",
      "input": "class Animal {} class Dog extends Animal {} Animal animal = new Dog();",
      "expected_output": "animal instanceof Dog 返回 true",
      "assertion": "检查Dog对象可以向上转型为Animal类型"
    },
    {
      "case_id": "TC4",
      "description": "测试引用类型之间的向下转型（需要显式转换）",
      "input": "Animal animal = new Dog(); Dog dog = (Dog) animal;",
      "expected_output": "dog instanceof Dog 返回 true",
      "assertion": "检查Animal对象向下转型为Dog类型成功"
    },
    {
      "case_id": "TC5",
      "description": "测试向下转型失败（ClassCastException）",
      "input": "Animal animal = new Animal(); Dog dog = (Dog) animal;",
      "expected_output": "抛出ClassCastException",
      "assertion": "检查当对象不是目标类型时，向下转型抛出异常"
    },
    {
      "case_id": "TC6",
      "description": "测试包装类与基本数据类型之间的自动装箱和拆箱",
      "input": "Integer e = 5; int f = e;",
      "expected_output": "f = 5",
      "assertion": "检查Integer到int的自动拆箱是否正确"
    },
    {
      "case_id": "TC7",
      "description": "测试字符串到基本数据类型的转换（如Integer.parseInt）",
      "input": "String str = \"123\"; int g = Integer.parseInt(str);",
      "expected_output": "g = 123",
      "assertion": "检查字符串解析为int是否正确"
    },
    {
      "case_id": "TC8",
      "description": "测试数组类型转换（如Object[]到String[]）",
      "input": "Object[] objArray = new String[]{\"hello\"}; String[] strArray = (String[]) objArray;",
      "expected_output": "strArray[0] = \"hello\"",
      "assertion": "检查Object数组向下转型为String数组成功"
    }
  ],
  "notes": "这些测试用例覆盖了Java类型转换的主要场景，包括基本数据类型、引用类型、包装类和数组。建议使用JUnit或其他测试框架执行，并验证底层逻辑如类型提升、截断、多态和异常处理。"
}

